def _get_next_run_safe(self, scheduler) -> Optional[str]:
    """Safely get next run time from scheduler."""
    if scheduler is None:
        return None
    try:
        next_run = scheduler.get_next_scheduled_run()
        return next_run.isoformat() if next_run else None
    except Exception:
        return None

